function powersUpTo(k, lim){
  const arr=[]; for(let x=1; ; x++){ const v=Math.pow(x,k); if(v>lim) break; arr.push({x,v}); }
  return arr;
}
function decomposeMin(n, k, sMax=40){
  const P = powersUpTo(k, n);
  for(let s=1; s<=sMax; s++){
    const path=[];
    function go(rem, left, startIdx){
      if(left===0) return rem===0;
      if(rem < 0) return false;
      // need rem <= left * P[startIdx].v (else not enough)
      if(startIdx<0) return false;
      if(P[startIdx].v * left < rem) return false;
      for(let i=startIdx; i>=0; i--){
        const {x,v} = P[i];
        if(v > rem) continue;
        path.push(x);
        if(go(rem-v, left-1, i)) return true;
        path.pop();
      }
      return false;
    }
    if(go(n, s, P.length-1)) return {s, path:path.slice()};
  }
  return null;
}
const kSel=$('#w-k'), nIn=$('#w-n'), go=$('#w-go'), out=$('#w-out');
function render(){
  const k = +kSel.value;
  const n = Math.max(1, Math.min(2000, +nIn.value|0));
  const res = decomposeMin(n, k);
  if(!res){ out.textContent = `no decomposition found for n=${n}, k=${k} with s≤40.`; return; }
  const terms = res.path.map(x => `${x}^${k}`).join(' + ');
  const counts = {};
  res.path.forEach(x => counts[x] = (counts[x]||0)+1);
  const grouped = Object.keys(counts).sort((a,b)=>+b-+a)
    .map(x => (counts[x]>1 ? `${counts[x]}·${x}^${k}` : `${x}^${k}`))
    .join(' + ');
  out.textContent =
    `k = ${k},  n = ${n}\n`+
    `minimum # of ${k}-th powers: ${res.s}\n`+
    `decomposition: ${n} = ${terms}\n`+
    `grouped:       ${n} = ${grouped}`;
}
go.addEventListener('click', render);
nIn.addEventListener('keypress', e=>{ if(e.key==='Enter') render(); });
kSel.addEventListener('change', render);
render();

