  {k:9,  g:548, Glo:13, Ghi:50},
  {k:10, g:1079,Glo:12, Ghi:59}
];
const svg = $('#gg-svg'), out = $('#gg-out');
const W=620, H=260, pad=38;
const maxY = Math.max(...data.map(d=>d.g));
// log scale for contrast
const yS = v => (H-pad) - (Math.log(1+v)/Math.log(1+maxY))*(H-pad-pad/2);
// axes
svg.appendChild(SVG('line',{x1:pad,y1:H-pad,x2:W-pad,y2:H-pad,stroke:'var(--line)','stroke-width':1}));
svg.appendChild(SVG('line',{x1:pad,y1:pad/2,x2:pad,y2:H-pad,stroke:'var(--line)','stroke-width':1}));
// y label
const ylab = SVG('text',{x:pad-6,y:pad-2,'text-anchor':'end','font-size':11,fill:'var(--mute)'});
ylab.textContent = 'log scale'; svg.appendChild(ylab);
// y ticks at 4, 10, 40, 100, 400, 1000
for(const v of [4,10,40,100,400,1000]){
  if(v>maxY) continue;
  const y = yS(v);
  svg.appendChild(SVG('line',{x1:pad-4,y1:y,x2:pad,y2:y,stroke:'var(--mute)','stroke-width':1}));
  const t = SVG('text',{x:pad-6,y:y+4,'text-anchor':'end','font-size':10,fill:'var(--mute)'});
  t.textContent = v; svg.appendChild(t);
}
const slot = (W - 2*pad) / data.length;
data.forEach((d, i) => {
  const cx = pad + slot*(i+0.5);
  const bw = slot*0.36;
  // g(k) — yellow
  const yg = yS(d.g);
  svg.appendChild(SVG('rect',{x:cx-bw-2,y:yg,width:bw,height:(H-pad)-yg,fill:'var(--yellow)',opacity:0.85,rx:2}));
  // G(k) — green (midpoint of interval)
  const Gmid = (d.Glo + d.Ghi)/2;
  const yG = yS(Gmid);
  svg.appendChild(SVG('rect',{x:cx+2,y:yG,width:bw,height:(H-pad)-yG,fill:'var(--green)',opacity:0.85,rx:2}));
  // if interval, draw a vertical range bar
  if(d.Glo !== d.Ghi){
    const ylo = yS(d.Glo), yhi = yS(d.Ghi);
    svg.appendChild(SVG('line',{x1:cx+2+bw/2,y1:ylo,x2:cx+2+bw/2,y2:yhi,stroke:'var(--ink)','stroke-width':1.5,'stroke-linecap':'round'}));
    svg.appendChild(SVG('line',{x1:cx+2+bw/2-5,y1:yhi,x2:cx+2+bw/2+5,y2:yhi,stroke:'var(--ink)','stroke-width':1.5}));
    svg.appendChild(SVG('line',{x1:cx+2+bw/2-5,y1:ylo,x2:cx+2+bw/2+5,y2:ylo,stroke:'var(--ink)','stroke-width':1.5}));
  }
  // k label
  const t = SVG('text',{x:cx,y:H-pad+16,'text-anchor':'middle','font-size':11,fill:'var(--mute)'});
  t.textContent = `k=${d.k}`; svg.appendChild(t);
  // value labels above bars (small)
  const tg = SVG('text',{x:cx-bw/2-2,y:yg-3,'text-anchor':'middle','font-size':9,fill:'var(--yellow)'});
  tg.textContent = d.g; svg.appendChild(tg);
  const tG = SVG('text',{x:cx+bw/2+2,y:yG-3,'text-anchor':'middle','font-size':9,fill:'var(--green)'});
  tG.textContent = (d.Glo===d.Ghi) ? d.Glo : `${d.Glo}–${d.Ghi}`;
  svg.appendChild(tG);
  // invisible hit rect for tooltip
  const hit = SVG('rect',{x:cx-slot/2,y:pad/2,width:slot,height:H-pad-pad/2,fill:'transparent'});
  hit.addEventListener('mouseenter', ()=>{
    const Gtxt = d.Glo===d.Ghi ? `${d.Glo}` : `in [${d.Glo}, ${d.Ghi}]`;
    out.textContent = `k = ${d.k}:   g(k) = ${d.g},   G(k) = ${Gtxt}.   ratio g/G ≈ ${(d.g/((d.Glo+d.Ghi)/2)).toFixed(2)}.`;
  });
  svg.appendChild(hit);
});
// legend
const lg = SVG('g',{});
lg.appendChild(SVG('rect',{x:pad+4,y:pad/2-2,width:10,height:10,fill:'var(--yellow)'}));
const lt1 = SVG('text',{x:pad+18,y:pad/2+7,'font-size':11,fill:'var(--mute)'});
lt1.textContent = 'g(k)'; lg.appendChild(lt1);
lg.appendChild(SVG('rect',{x:pad+58,y:pad/2-2,width:10,height:10,fill:'var(--green)'}));
const lt2 = SVG('text',{x:pad+72,y:pad/2+7,'font-size':11,fill:'var(--mute)'});
lt2.textContent = 'G(k)'; lg.appendChild(lt2);
svg.appendChild(lg);

