const svg = $('#c-svg'), kSel = $('#c-k'), mSl = $('#c-M'),
      mLab = $('#c-mlab'), out = $('#c-out');
const W=620, H=300, padL=40, padR=20, padT=16, padB=36;
const innerW = W - padL - padR, innerH = H - padT - padB;
function draw(){
  svg.innerHTML = '';
  const k = +kSel.value;
  const M = +mSl.value;
  mLab.textContent = `M = ${M}, so N ≈ ${Math.round(Math.pow(M,k))}`;
  // Sample |f(α)|² normalized
  const NSAMP = 600;
  const xs = new Float64Array(NSAMP);
  const ys = new Float64Array(NSAMP);
  let maxAbs = 0;
  for(let i=0; i<NSAMP; i++){
    const alpha = i/(NSAMP-1);
    let re=0, im=0;
    for(let n=1; n<=M; n++){
      const theta = 2*Math.PI * alpha * Math.pow(n,k);
      re += Math.cos(theta);
      im += Math.sin(theta);
    }
    const mag = Math.hypot(re,im);
    xs[i] = alpha;
    ys[i] = mag;
    if(mag>maxAbs) maxAbs = mag;
  }
  // axes
  svg.appendChild(SVG('line',{x1:padL,y1:H-padB,x2:W-padR,y2:H-padB,stroke:'var(--line)','stroke-width':1}));
  svg.appendChild(SVG('line',{x1:padL,y1:padT,x2:padL,y2:H-padB,stroke:'var(--line)','stroke-width':1}));
  // x ticks
  for(let i=0;i<=10;i++){
    const x = padL + (i/10)*innerW;
    svg.appendChild(SVG('line',{x1:x,y1:H-padB,x2:x,y2:H-padB+4,stroke:'var(--mute)'}));
    const t = SVG('text',{x,y:H-padB+16,'text-anchor':'middle','font-size':10,fill:'var(--mute)'});
    t.textContent = (i/10).toFixed(1); svg.appendChild(t);
  }
  const xAxLbl = SVG('text',{x:W-padR, y:H-padB+30,'text-anchor':'end','font-size':11,fill:'var(--mute)'});
  xAxLbl.textContent = 'α ∈ [0,1]'; svg.appendChild(xAxLbl);
  // y axis label
  const yLbl = SVG('text',{x:padL+4,y:padT+12,'font-size':11,fill:'var(--mute)'});
  yLbl.textContent = '|f(α)|  (peak ≈ M = '+M+')';
  svg.appendChild(yLbl);
  // major-arc highlight: rationals a/q for q=1..6
  const QMAX = 6;
  for(let q=1; q<=QMAX; q++){
    for(let a=0; a<=q; a++){
      if(a!==0 && a!==q){
        // only one rep
        // gcd check
        let g=a, b=q; while(b){ const t=b; b=g%b; g=t; }
        if(g!==1) continue;
      }
      const alpha = a/q;
      const xPix = padL + alpha*innerW;
      // arc half-width ~ 1/(q*M^((k-1))): here just visual scale
      const half = Math.max(3, 40/(q*q));
      const xL = Math.max(padL, xPix-half), xR = Math.min(W-padR, xPix+half);
      svg.appendChild(SVG('rect',{
        x:xL, y:padT, width:xR-xL, height:innerH,
        fill: q===1?'var(--yellow)':q<=3?'var(--green)':'var(--cyan)',
        opacity: 0.08
      }));
      if(q<=3){
        // label above axis
        const lab = SVG('text',{x:xPix,y:padT+24,'text-anchor':'middle','font-size':10,
          fill: q===1?'var(--yellow)':'var(--green)'});
        lab.textContent = q===1 ? (a===0?'0':'1') : `${a}/${q}`;
        svg.appendChild(lab);
      }
    }
  }
  // curve |f(α)|
  let d = '';
  for(let i=0;i<NSAMP;i++){
    const x = padL + xs[i]*innerW;
    const y = (H-padB) - (ys[i]/maxAbs)*innerH*0.92;
    d += (i===0?'M':'L') + x.toFixed(2) + ' ' + y.toFixed(2) + ' ';
  }
  svg.appendChild(SVG('path',{d, fill:'none', stroke:'var(--pink)', 'stroke-width':1.3}));
  // mean line: ∫₀¹ |f|² dα = M, so rms ≈ √M
  const rms = Math.sqrt(M);
  const yRms = (H-padB) - (rms/maxAbs)*innerH*0.92;
  svg.appendChild(SVG('line',{x1:padL,y1:yRms,x2:W-padR,y2:yRms,
    stroke:'var(--mute)','stroke-width':1,'stroke-dasharray':'4 3'}));
  const trms = SVG('text',{x:W-padR-2,y:yRms-4,'text-anchor':'end','font-size':10,fill:'var(--mute)'});
  trms.textContent = `rms √M ≈ ${rms.toFixed(2)}`; svg.appendChild(trms);
  // output
  const fracs = [];
  for(let q=2;q<=QMAX;q++) for(let a=1;a<q;a++){
    let g=a, b=q; while(b){ const t=b; b=g%b; g=t; }
    if(g===1) fracs.push(`${a}/${q}`);
  }
  out.textContent =
    `k = ${k},  M = ⌊N^{1/k}⌋ = ${M},  N ≈ ${Math.round(Math.pow(M,k))}.\n`+
    `peak |f(α)| ≈ ${maxAbs.toFixed(2)} at α = 0 (and every integer).\n`+
    `highlighted rationals a/q (q ≤ ${QMAX}): 0, 1, ${fracs.join(', ')}.\n`+
    `on major arcs (near small-denom rationals) |f(α)| is anomalously large;\n`+
    `on minor arcs Weyl's inequality gives |f(α)| ≪ M · M^{-σ_k}, σ_k = 2^{1-k}.`;
}
kSel.addEventListener('change', draw);
mSl.addEventListener('input', draw);
draw();

