        let g=a, b=q; while(b){ const t=b; b=g%b; g=t; }
        if(g!==1) continue;
      }
      const alpha = a/q;
      const xPix = padL + alpha*innerW;
      // arc half-width ~ 1/(q*M^((k-1))): here just visual scale
      const half = Math.max(3, 40/(q*q));
      const xL = Math.max(padL, xPix-half), xR = Math.min(W-padR, xPix+half);
      svg.appendChild(SVG('rect',{
        x:xL, y:padT, width:xR-xL, height:innerH,
        fill: q===1?'var(--yellow)':q<=3?'var(--green)':'var(--cyan)',
        opacity: 0.08
      }));
      if(q<=3){
        // label above axis
        const lab = SVG('text',{x:xPix,y:padT+24,'text-anchor':'middle','font-size':10,
          fill: q===1?'var(--yellow)':'var(--green)'});
        lab.textContent = q===1 ? (a===0?'0':'1') : `${a}/${q}`;
        svg.appendChild(lab);
      }
    }
  }
  // curve |f(α)|
  let d = '';
  for(let i=0;i<NSAMP;i++){
    const x = padL + xs[i]*innerW;
    const y = (H-padB) - (ys[i]/maxAbs)*innerH*0.92;
    d += (i===0?'M':'L') + x.toFixed(2) + ' ' + y.toFixed(2) + ' ';
  }
  svg.appendChild(SVG('path',{d, fill:'none', stroke:'var(--pink)', 'stroke-width':1.3}));
  // mean line: ∫₀¹ |f|² dα = M, so rms ≈ √M
  const rms = Math.sqrt(M);
  const yRms = (H-padB) - (rms/maxAbs)*innerH*0.92;
  svg.appendChild(SVG('line',{x1:padL,y1:yRms,x2:W-padR,y2:yRms,
    stroke:'var(--mute)','stroke-width':1,'stroke-dasharray':'4 3'}));
  const trms = SVG('text',{x:W-padR-2,y:yRms-4,'text-anchor':'end','font-size':10,fill:'var(--mute)'});
  trms.textContent = `rms √M ≈ ${rms.toFixed(2)}`; svg.appendChild(trms);
  // output
  const fracs = [];
  for(let q=2;q<=QMAX;q++) for(let a=1;a<q;a++){
    let g=a, b=q; while(b){ const t=b; b=g%b; g=t; }
    if(g===1) fracs.push(`${a}/${q}`);
  }
  out.textContent =
    `k = ${k},  M = ⌊N^{1/k}⌋ = ${M},  N ≈ ${Math.round(Math.pow(M,k))}.\n`+
    `peak |f(α)| ≈ ${maxAbs.toFixed(2)} at α = 0 (and every integer).\n`+
    `highlighted rationals a/q (q ≤ ${QMAX}): 0, 1, ${fracs.join(', ')}.\n`+
    `on major arcs (near small-denom rationals) |f(α)| is anomalously large;\n`+
    `on minor arcs Weyl's inequality gives |f(α)| ≪ M · M^{-σ_k}, σ_k = 2^{1-k}.`;
}
kSel.addEventListener('change', draw);
mSl.addEventListener('input', draw);
draw();

const kSel = $('#gs-k'), qIn = $('#gs-q'), aIn = $('#gs-a'), out = $('#gs-out');
function gcd(a,b){ a=Math.abs(a); b=Math.abs(b); while(b){ const t=b; b=a%b; a=t;} return a; }
function render(){
  const k = +kSel.value;
  const q = Math.max(1, Math.min(40, +qIn.value|0));
  const a = Math.max(0, Math.min(q, +aIn.value|0));
  let re=0, im=0;
  const terms=[];
  for(let r=1; r<=q; r++){
    const v = Math.pow(r,k) % (q*100); // avoid float issues for small q
    const theta = 2*Math.PI*(a*v)/q;
    re += Math.cos(theta);
    im += Math.sin(theta);
    if(r<=6 || r===q) terms.push(`e(${a}·${r}^${k}/${q})`);
  }
  const mag = Math.hypot(re,im);
  const g = gcd(a,q);
  const red = g===1 ? 'reduced' : `NOT reduced (gcd(a,q)=${g})`;
  // Compare with known bounds: |S(a,q)| ≤ C·q^{1-1/k} for (a,q)=1
  const bound = Math.pow(q, 1 - 1/k);
  out.textContent =
    `S(${a},${q}) = ${terms.slice(0,6).join(' + ')}${q>6?' + …':''}\n`+
    `           = ${re.toFixed(4)} + ${im.toFixed(4)}i\n`+
    `|S(a,q)|   = ${mag.toFixed(4)}\n`+
    `bound       |S(a,q)| ≤ C·q^{1-1/k} = q^{${(1-1/k).toFixed(3)}} = ${bound.toFixed(3)}\n`+
    `(a,q):     ${red}   ${g===1 && mag > bound*1.5 ? '— bound is loose for small q' : ''}`;
}
kSel.addEventListener('change', render);
qIn.addEventListener('input', render);
aIn.addEventListener('input', render);
render();

